arguments.command:
cat > /tmp/stackalloc_test/Program.cs << 'EOF'
Span<nint> a = stackalloc nint[4];
a[0] = 1; a[1] = 2; a[2] = 3; a[3] = 4;
Console.WriteLine($"nint span length: {a.Length}, sum: {a[0]+a[1]+a[2]+a[3]}");

Span<nuint> b = stackalloc nuint[3];
b[0] = 10; b[1] = 20; b[2] = 30;
Console.WriteLine($"nuint span length: {b.Length}, sum: {b[0]+b[1]+b[2]}");

Console.WriteLine($"sizeof(nint): {sizeof(nint)}, sizeof(nuint): {sizeof(nuint)}");
EOF
